cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'admin123',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status === 200) {
    expect(resp.body.success).to.be.true;
    expect(resp.body.data.tipo).to.equal('admin');
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'WRONG',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    expect(resp.status).to.equal(401);
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'test@test.com',
    password: 'pass',
    tipo: 'hacker'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    expect(resp.status).to.equal(400);
  }
});

cy.clearLocalStorage();
cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
cy.url().should('include', '/dashboard');
cy.reload();
cy.url().should('include', '/dashboard');

cy.clearLocalStorage();
cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
cy.get('[data-cy="btn-logout"]').click({
  force: true
});
cy.window().then(win => {
  expect(win.localStorage.getItem('auth')).to.be.null;
});

